class TimestampHeaderParser {
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    public static String extractTimestamp(SOAPMessage message) throws SOAPException {
        if (message == null) return null;
        SOAPHeader header = message.getSOAPHeader();
        if (header == null) return null;

        @SuppressWarnings("unchecked")
        java.util.Iterator<SOAPHeaderElement> it = header.examineAllHeaderElements();
        while (it.hasNext()) {
            SOAPHeaderElement element = it.next();
            QName name = element.getElementQName();
            if ("Security".equals(name.getLocalPart()) && WSSE_NS.equals(name.getNamespaceURI())) {
                @SuppressWarnings("unchecked")
                java.util.Iterator<?> secChildren = element.getChildElements();
                while (secChildren.hasNext()) {
                    Object child = secChildren.next();
                    if (child instanceof SOAPElement) {
                        SOAPElement secEl = (SOAPElement) child;
                        QName childName = secEl.getElementQName();
                        if ("Timestamp".equals(childName.getLocalPart()) && WSU_NS.equals(childName.getNamespaceURI())) {
                            String created = getChildText(secEl, "Created", WSU_NS);
                            String expires = getChildText(secEl, "Expires", WSU_NS);
                            if (created != null && expires != null) {
                                return created + "|" + expires;
                            }
                        }
                    }
                }
            }
        }
        return null;
    }

    private static String getChildText(SOAPElement parent, String localName, String ns) {
        @SuppressWarnings("unchecked")
        java.util.Iterator<?> it = parent.getChildElements(new QName(ns, localName));
        while (it.hasNext()) {
            Object child = it.next();
            if (child instanceof SOAPElement) {
                return ((SOAPElement) child).getValue();
            }
        }
        return null;
    }
}

class TimestampReplayProtector {
    private final Duration allowedSkew;
    private final Map<String, Instant> seen = new HashMap<>();

    public TimestampReplayProtector(Duration allowedSkew) {
        this.allowedSkew = allowedSkew;
    }

    public synchronized boolean validateAndRegister(String timestampPair) {
        if (timestampPair == null || timestampPair.trim().isEmpty()) return false;
        String[] parts = timestampPair.split("\\|", 2);
        if (parts.length != 2) return false;

        Instant created;
        Instant expires;
        try {
            created = Instant.parse(parts[0]);
            expires = Instant.parse(parts[1]);
        } catch (Exception e) {
            return false;
        }

        Instant now = Instant.now();
        if (created.isAfter(now.plus(allowedSkew))) return false;
        if (expires.isBefore(now.minus(allowedSkew))) return false;
        if (expires.isBefore(created)) return false;

        String key = parts[0] + "|" + parts[1];
        if (seen.containsKey(key)) return false;
        seen.put(key, now);
        cleanup(now);
        return true;
    }

    private void cleanup(Instant now) {
        seen.entrySet().removeIf(e -> e.getValue().plus(allowedSkew.multipliedBy(2)).isBefore(now));
    }
}

